@module editorRender  src=editorRender.lua  loc=217  sha=9a303bd  mode=chunk  self=er
@deps swingEditor, temperEditor, cmgr, chrome, gui, modalHost

# Invariants & contracts
  @contract  render-only; owns pane-selection UI state; reaches the swing/temper panes, never cm/ds  @ 9
  @contract  body editor — focusState always page-suppresses (root globals stay live, page bindings off)  @ 10

# Shapes
  @shape  libraryTreeSpec = { x, y, h, label, active={{col,name}}, project={name}, global={name}, synthetic={[name]=true}, undeletable={[name]=true}, sel={tier,name}, dirty?:bool, onSelect(tier,name), onNew(), onImport?(), onPromote(name), onDemote(name), onReset?(), onDelete(tier,name) }  @ 31
  @shape  ToolbarSegment = { id, render = fn(), visible? = fn() -> bool }  @ 141
  @shape  focusState = { suppressKbd:bool, pageSuppressed:bool, acceptCmds:bool }  @ 206

# Imports
  @require ImGui = 'imgui'  @ 15

# Private state
  @state ctx, uiFont, uiSize = gui.ctx, gui.uiFont, gui.fontSize.ui  @ 19
  @state pane = 'swing'  @ 21
  @state droppedIn = false  @ 24
  @state treeOpen = { project = true, global = true }  @ 81
  @state er = {}  @ 122
  @state toolbarSegments = {  @ 142

# Private functions
  @fn activePane()  @ 25
  @fn onClose()  @ 27
  -- Library tree palette (Active / Project / Global tiers; one per pane)
  @fn libraryActions(spec)  @ 35-68
      -- sel.tier scopes the action bar: a folder selection (name=nil) scopes add/import,
      -- a leaf arms dup/del. Active's 'select' button resolves an entry to its home tier.
  @fn libraryRow(spec, tier, name, label)  @ 72-79
      -- PushID(tier) scopes the row's ImGui id: a promoted entry appears in both
      -- Project and Global with the same label, which would otherwise collide.
  @fn libraryFolder(spec, tier, title, drawChildren)  @ 85-92
      -- Disclosure chip toggles the folder; the title row selects the tier (name=nil)
      -- so add/import scope to it, and now also toggles. Mirrors the sampler tree.
  @fn libraryTree(spec)  @ 94-120

# Public API (er:*)
  @api er:edit(lib, name)  @ 128-135
      -- Fast path: set the pane + selection; the editTuning/editSwing commands
      -- (which hold coord) switch the page. Mirrors samplePage's diveToSampler.
  @api er:unbind()  @ 139
      -- Page unbind (leaving the editor) ends the drop-in: the next entry must
      -- re-earn the Close affordance by coming through edit() again.
  @api er:toolbarSegments()  @ 172
  @api er:renderBody(_, w, h, dispatch)  @ 174-199
  @api er:renderStatusBar(_)  @ 201-204
  @api er:focusState()  @ 207-215

